def _read_workbench_bundle() -> str:
    repo_root = Path(__file__).resolve().parents[1]
    paths = [
        repo_root / "ea/app/templates/app/property_decision_workbench.html",
        repo_root / "ea/app/templates/app/_property_results_list.html",
        repo_root / "ea/app/templates/app/_property_running_panel.html",
        repo_root / "ea/app/templates/app/_property_search_agents_panel.html",
        repo_root / "ea/app/templates/app/_property_selected_review_panel.html",
        repo_root / "ea/app/templates/app/_property_workbench_script.html",
        repo_root / "ea/app/templates/app/_property_workbench_brief_script.html",
        repo_root / "ea/app/templates/app/_property_workbench_feedback_script.html",
    ]
    return "\n".join(path.read_text(encoding="utf-8") for path in paths if path.exists())


def _assert_billing_fail_closed(response, *, marker: str = "The billing portal is still being connected.") -> None:
    if response.status_code in {303, 307}:
        assert response.headers["location"] == "/app/account?billing=1#delivery"
        return
    assert response.status_code == 503
    assert "Billing portal unavailable" in response.text
    assert marker in response.text
    assert "Your PropertyQuarry access stays active from the account page." in response.text


def _use_propertyquarry_release_probe_context(client, *, principal_id: str) -> None:
    context = RequestContext(
        principal_id=principal_id,
        authenticated=True,
        auth_source="propertyquarry_release_probe",
    )
    client.app.dependency_overrides[get_request_context] = lambda: context
    client.app.dependency_overrides[get_request_context_if_available] = lambda: context


class _RenderedInteractiveElementParser(HTMLParser):
    def __init__(self) -> None:
        super().__init__()
        self.elements: list[tuple[str, dict[str, str], str]] = []
        self._stack: list[tuple[str, int | None]] = []

    def handle_starttag(self, tag: str, attrs: list[tuple[str, str | None]]) -> None:
        attr_map = {key: value or "" for key, value in attrs}
        is_clickable = (
            tag in {"a", "button", "form", "input", "summary"}
            or str(attr_map.get("role") or "").strip().lower() == "button"
        )
        element_index: int | None = None
        if is_clickable:
            element_index = len(self.elements)
            self.elements.append((tag, attr_map, ""))
        if tag not in {"area", "base", "br", "col", "embed", "hr", "img", "input", "link", "meta", "source", "track", "wbr"}:
            self._stack.append((tag, element_index))

    def handle_endtag(self, tag: str) -> None:
        for index in range(len(self._stack) - 1, -1, -1):
            if self._stack[index][0] == tag:
                del self._stack[index:]
                return

    def handle_data(self, data: str) -> None:
        text = str(data or "").strip()
        if not text:
            return
        for _tag, element_index in reversed(self._stack):
            if element_index is None:
                continue
            tag, attrs, current = self.elements[element_index]
            self.elements[element_index] = (tag, attrs, f"{current} {text}".strip())
            return


def test_propertyquarry_app_templates_do_not_reintroduce_legacy_dark_theme_tokens() -> None:
    repo_root = Path(__file__).resolve().parents[1]
    template_paths = [
        repo_root / "ea/app/templates/base_console.html",
        repo_root / "ea/app/templates/console_shell.html",
        repo_root / "ea/app/templates/app/object_detail.html",
        repo_root / "ea/app/templates/app/people_detail.html",
        repo_root / "ea/app/templates/app/commitment_candidate_review.html",
        repo_root / "ea/app/templates/app/property_decision_workbench.html",
    ]
    forbidden_tokens = (
        "rgba(18, 23, 34",
        "rgba(15, 19, 26",
        "rgba(49, 60, 77",
        "#070a10",
        "#0a0d14",
        "#0b1017",
        "360 not ready",
        "not scheduled yet",
    )
    for template_path in template_paths:
        body = template_path.read_text(encoding="utf-8")
        assert "background: var(--panel);" in body or "background: var(--pq-paper);" in body
        for token in forbidden_tokens:
            assert token not in body, f"{token!r} leaked into {template_path.relative_to(repo_root)}"


