def test_property_research_legacy_path_redirects_to_canonical_candidate_route() -> None:
    client = build_property_client(principal_id="pq-research-legacy-redirect")
    start_workspace(client, mode="personal", workspace_name="PropertyQuarry")

    response = client.get(
        "/app/research/run-42/altbau-u6",
        params={"investment": 1},
        headers={"host": "propertyquarry.com"},
        follow_redirects=False,
    )

    assert response.status_code == 307
    location = response.headers["location"]
    parsed = urllib.parse.urlsplit(location)
    assert parsed.path == "/app/research/altbau-u6"
    assert urllib.parse.parse_qs(parsed.query) == {"run_id": ["run-42"], "investment": ["1"]}


def test_propertyquarry_primary_surfaces_have_no_dead_click_targets_or_generic_noise() -> None:
    client = build_property_client(principal_id="pq-rendered-surface-click-audit")
    start_workspace(client, mode="personal", workspace_name="PropertyQuarry")
    public_client = build_property_client(principal_id="pq-rendered-public-click-audit")
    public_client.headers.pop("X-EA-Principal-ID", None)
    audited_paths = (
        (client, "/app/search"),
        (client, "/app/properties"),
        (client, "/app/shortlist"),
        (client, "/app/agents"),
        (client, "/app/account"),
        (client, "/app/billing"),
        (client, "/app/settings/plan"),
        (client, "/app/settings/support"),
        (client, "/app/settings/trust"),
        (client, "/app/settings/usage"),
        (client, "/app/settings/outcomes"),
        (client, "/data-deletion"),
        (public_client, "/"),
        (public_client, "/?home=1"),
        (public_client, "/sign-in"),
        (public_client, "/pricing"),
        (public_client, "/data-deletion"),
    )
    protected_paths = (
        "/app/search",
        "/app/shortlist",
    )
    noisy_phrases = (
        "Signal later",
        "Use stored feedback preferences",
        "Manage feedback preferences",
        "Preference profile",
        "Billing truth",
        "Plan and limits",
        "Plan unit",
        "entitlement truth",
        "Make plan, limits",
        "worker capacity",
        "provider breadth",
        "What this plan can actually run",
        "How this plan affects real runs",
        "live search workers",
        "Fleet digest",
        "Executive Assistant",
        "memo items",
        "queue items",
        "operator load",
        "operator center",
        "EA queued",
        "Open automation",
        "office loop",
        "Refresh delivery",
        "support tooling",
        "workspace access links",
        "workspace access method",
        "workspace records",
        "Office-loop proof",
        "release proof",
        "Journey proof",
        "No proof summary",
        "Gate state",
        "Passed checks",
        "source check",
        "Run health and coverage",
        "search posture",
        "Search posture",
        "Account posture",
        "Latest run posture",
        "Saved posture",
        "billing posture",
        "Plan and billing posture",
        "Energy posture",
        "running-cost posture",
        "authority posture",
        "governed review",
        "workspace diagnostics bundle",
        "Workspace diagnostics bundle",
        "Everyday preferences, schools, childcare, and local fit that should stay explicit.",
        "workspace preferences",
        "generated workflow data",
        "generated workflow records",
        "generated drafts",
        "operational artifacts tied to your workspace",
        "operational artifacts tied to your account",
        "Support posture",
        "Runtime posture",
        "Runtime and provider posture",
        "Provider risk",
        "provider posture",
        "Health score",
        "Fix verification",
        "Channel receipt",
        "Install receipt",
        "Support bundle",
        "Export bundle",
        "Open bundle",
        "Grounded packet",
        "Outcome posture",
        "follow-up artifacts",
        "Artifacts ready",
        "Provider failures",
        "proof of value",
        "Supporting proof",
    )
    for audit_client, path in audited_paths:
        response = audit_client.get(path, headers={"host": "propertyquarry.com"})
        if path == "/app/billing" and response.status_code != 200:
            _assert_billing_fail_closed(response)
            continue
        assert response.status_code == 200, path
        if path == "/app/billing":
            assert "Billing portal unavailable" not in response.text
            assert "Log out" in response.text
        response_ids = set(re.findall(r'id="([^"]+)"', response.text))
        rendered_text = re.sub(
            r"<script.*?</script>|<style.*?</style>",
            " ",
            response.text,
            flags=re.DOTALL | re.IGNORECASE,
        )
        rendered_text = re.sub(r"<[^>]+>", " ", rendered_text)
        rendered_text = re.sub(r"\s+", " ", rendered_text)
        for phrase in noisy_phrases:
            assert phrase.lower() not in rendered_text.lower(), f"{phrase!r} leaked into {path}"

        parser = _RenderedInteractiveElementParser()
        parser.feed(response.text)
        for tag, attrs, text in parser.elements:
            if tag == "a":
                href = str(attrs.get("href") or "").strip()
                assert href, f"anchor without href on {path}: {text!r}"
                if href.startswith("#"):
                    assert href.strip() != "#", f"anchor with bare hash on {path}: {text!r}"
                    assert href[1:] in response_ids, f"anchor points to missing target on {path}: {text!r} -> {href}"
                    continue
                assert not href.lower().startswith("javascript:"), f"javascript link on {path}: {text!r}"
                if str(attrs.get("target") or "").strip().lower() == "_blank":
                    rel_tokens = {
                        token.strip().lower()
                        for token in str(attrs.get("rel") or "").split()
                        if token.strip()
                    }
                    assert rel_tokens.intersection({"noopener", "noreferrer"}), f"external tab link lacks safe rel on {path}: {text!r}"
                if audit_client is public_client and href.split("#", 1)[0] in protected_paths:
                    assert "current session" not in text.lower(), f"anonymous page links current-session action to protected route on {path}"
            if tag == "button" and "disabled" not in attrs:
                button_type = str(attrs.get("type") or "submit").strip().lower() or "submit"
                has_data_handler = any(key.startswith("data-") for key in attrs)
                has_form_action = bool(str(attrs.get("formaction") or "").strip())
                assert (
                    button_type in {"submit", "reset"}
                    or has_data_handler
                    or has_form_action
                    or bool(str(attrs.get("onclick") or "").strip())
                    or bool(str(attrs.get("popovertarget") or "").strip())
                    or bool(str(attrs.get("aria-controls") or "").strip())
                ), f"enabled button without action wiring on {path}: {text!r}"
            if tag == "input" and "disabled" not in attrs:
                input_type = str(attrs.get("type") or "text").strip().lower() or "text"
                if input_type in {"button", "image"}:
                    assert (
                        any(key.startswith("data-") for key in attrs)
                        or bool(str(attrs.get("formaction") or "").strip())
                        or bool(str(attrs.get("onclick") or "").strip())
                    ), f"enabled input button without action wiring on {path}: {attrs!r}"
            if tag not in {"a", "button"} and str(attrs.get("role") or "").strip().lower() == "button":
                assert (
                    any(key.startswith("data-") for key in attrs)
                    or bool(str(attrs.get("onclick") or "").strip())
                ), f"custom role=button without action wiring on {path}: {text!r}"
            if tag == "form":
                action = str(attrs.get("action") or "").strip()
                method = str(attrs.get("method") or "get").strip().lower() or "get"
                has_data_handler = any(key.startswith("data-") for key in attrs)
                assert action or has_data_handler, f"form without action or client handler on {path}"
                assert not action.lower().startswith("javascript:"), f"javascript form action on {path}: {action!r}"
                assert method in {"get", "post", "dialog"}, f"unexpected form method on {path}: {method!r}"


def test_propertyquarry_invitations_surface_uses_collaborator_language() -> None:
    client = build_property_client(principal_id="pq-rendered-invitation-language")
    start_workspace(client, mode="personal", workspace_name="PropertyQuarry")

    response = client.get("/app/settings/invitations", headers={"host": "propertyquarry.com"})
    assert response.status_code == 200

    rendered_text = re.sub(
        r"<script.*?</script>|<style.*?</style>",
        " ",
        response.text,
        flags=re.DOTALL | re.IGNORECASE,
    )
    rendered_text = re.sub(r"<[^>]+>", " ", rendered_text)
    rendered_text = re.sub(r"\s+", " ", rendered_text)

    assert "Collaborator" in rendered_text
    assert "Account owner" in rendered_text
    assert "operator invitation" not in rendered_text.lower()
    assert "operator one" not in rendered_text.lower()
    assert "another reviewer or operator" not in rendered_text.lower()


