def test_propertyquarry_visual_requests_stay_user_initiated_and_idempotent() -> None:
    body = _read_workbench_bundle()
    research_detail = (
        Path(__file__).resolve().parents[1] / "ea/app/templates/app/property_research_detail.html"
    ).read_text(encoding="utf-8")

    assert "auto_deliver: false" in body
    assert "allow_floorplan_only: true" in body
    assert "keepButtonDisabled = true" in body
    assert "button.disabled = keepButtonDisabled" in body
    assert "data-pw-visual-ready-url" in body
    assert "const requestedReadyUrl = requestKind === 'flythrough' ? nextFlythroughUrl : nextTourUrl" in body
    assert "window.location.href = readyUrl" in body
    assert "button.setAttribute('data-pw-visual-state', requestedReadyUrl ? 'ready' : requestedStatus)" in body
    assert "Open walkthrough" in research_detail
    assert "Open flythrough" not in research_detail
    assert "const visualPendingStates = ['pending', 'queued', 'processing', 'running', 'in_progress', 'started', 'rendering', 'repairing'];" in research_detail
    assert "const isWaiting = visualPendingStates.includes(nextState);" in research_detail
    assert "button.disabled = isWaiting;" in research_detail
    assert "const resolvedFlythroughUrl = directHostedWalkthroughUrl(" in research_detail
    assert "const retryableTerminal = visualTerminalStates.includes(state) && !resolvedFlythroughUrl;" in research_detail
    assert "const openTourUrl = String(" in research_detail
    assert "const malformedReadyState = rawTourState === 'ready' && !openTourUrl;" in research_detail
    assert "? 'ready'" in research_detail
    assert ": (malformedReadyState ? 'blocked' : rawTourState || 'pending')" in research_detail
    assert "const retryableTerminal = visualTerminalStates.includes(state) && !openTourUrl;" in research_detail


def test_propertyquarry_register_surface_uses_property_search_language() -> None:
    client = build_property_client(principal_id="pq-register-copy")
    public_client = build_property_client(principal_id="pq-register-copy-public")
    public_client.headers.pop("X-EA-Principal-ID", None)

    page = client.get("/register", headers={"host": "propertyquarry.com"})
    pricing = client.get("/pricing", headers={"host": "propertyquarry.com"})
    sign_in = public_client.get("/sign-in", headers={"host": "propertyquarry.com"})
    public_pricing = public_client.get("/pricing", headers={"host": "propertyquarry.com"})
    signed_in_sign_in = client.get("/sign-in", headers={"host": "propertyquarry.com"})

    assert page.status_code == 200
    assert pricing.status_code == 200
    assert sign_in.status_code == 200
    assert public_pricing.status_code == 200
    assert signed_in_sign_in.status_code == 200
    assert "Set up your property search." in page.text
    assert "Finish setup" in page.text
    assert 'href="/app/search"' in page.text
    assert 'href="/app/search"' not in sign_in.text
    assert 'href="/sign-in/current-session"' not in sign_in.text
    assert "Open current session" not in sign_in.text
    assert ">Log out<" not in sign_in.text
    assert 'href="/app/search"' in signed_in_sign_in.text
    assert "Open search" in signed_in_sign_in.text
    assert 'href="/app/search"' in pricing.text
    assert "Your account is already active." in pricing.text
    assert (
        'href="/app/billing"' in pricing.text
        or 'data-pricing-upgrade="plus"' in pricing.text
        or 'data-pricing-upgrade="agent"' in pricing.text
        or 'href="https://billing.propertyquarry.com/account"' in pricing.text
    )
    assert 'href="/register"' not in pricing.text
    assert "Create account" not in pricing.text
    assert "Start free" in public_pricing.text
    assert 'href="/sign-in?signing_in=1"' in public_pricing.text
    assert "No payment required." in public_pricing.text
    assert "Already have an account?" in public_pricing.text
    assert 'action="/app/actions/sign-out"' in signed_in_sign_in.text
    assert ">Log out<" in signed_in_sign_in.text
    assert signed_in_sign_in.text.count('action="/app/actions/sign-out"') == 1
    assert signed_in_sign_in.text.count(">Log out<") == 1
    assert 'href="/register">Email sign-in</a>' not in signed_in_sign_in.text
    assert 'href="/app/properties">Open current session</a>' not in sign_in.text
    assert "Open current session" not in signed_in_sign_in.text
    assert signed_in_sign_in.text.count("Open search") == 1
    assert "Google?" not in sign_in.text
    assert "Facebook?" not in sign_in.text
    assert "Use the path that matches how you joined" not in sign_in.text
    assert "Identity only" not in sign_in.text
    assert "Identity-only." not in sign_in.text
    assert "Use a secure email link if your address already has access." in sign_in.text
    assert "You can also continue with an available provider." in sign_in.text
    assert "Any provider below reopens the same account or creates it automatically on first use." not in sign_in.text
    assert "Connected sign-in opens the same account or creates it the first time." not in sign_in.text
    for provider in ("Google", "Facebook", "ID Austria"):
        if f"Continue with {provider}" in sign_in.text:
            assert f"{provider} opens the same account and creates it if needed." in sign_in.text
    assert "Trusted device" not in sign_in.text
    assert "Private hardware access stays limited to approved devices." not in sign_in.text
    assert "Private hardware sign-in lane for approved devices." not in sign_in.text
    assert ">Restricted<" not in sign_in.text
    assert "verified rollout" not in sign_in.text
    assert ">Invite only<" not in sign_in.text
    assert "first useful memo" not in page.text
    assert 'data-milestone="commitments"' not in page.text
    assert "Executive Assistant" not in page.text
    assert "Executive Assistant" not in sign_in.text


