def test_property_provider_options_expose_homepage_links() -> None:
    options = property_market_catalog.provider_options(country_code="AT")
    willhaben = next(option for option in options if option["value"] == "willhaben")
    assert willhaben["homepage_url"] == "https://www.willhaben.at"
    community_signals = next(option for option in options if option["value"] == "community_signals_at")
    assert community_signals["search_ready"] is False
    assert community_signals["coming_soon"] is True
    assert community_signals["availability_note"] == "Coming soon"


def test_propertyquarry_search_surface_removes_cross_country_saved_providers() -> None:
    client = build_property_client(principal_id="pq-search-provider-country-gate")
    headers = {"host": "propertyquarry.com"}
    start_workspace(client, mode="personal", workspace_name="Provider Country Gate")

    saved = client.post(
        "/v1/onboarding/property-search/preferences",
        json={
            "country_code": "AT",
            "region_code": "vienna",
            "listing_mode": "rent",
            "location_query": "1010 Vienna",
            "selected_platforms": ["realestate_au", "willhaben"],
        },
        headers=headers,
    )
    assert saved.status_code == 200, saved.text

    response = client.get("/app/search", headers=headers)

    assert response.status_code == 200
    assert 'value="willhaben"' in response.text
    assert 'value="realestate_au"' not in response.text
    assert '"selected_platforms": ["realestate_au"' not in response.text
    assert '"selected_platforms": ["willhaben"]' in response.text
    assert 'value="willhaben" data-country-code="AT"' in response.text


def test_property_search_payload_filters_selected_providers_by_active_country() -> None:
    script = (Path(__file__).resolve().parents[1] / "ea/app/templates/app/_property_workbench_brief_script.html").read_text(encoding="utf-8")

    assert "const checkedProviderValuesForCountry = (form, countryCode, listingMode = 'rent') => {" in script
    assert "const providerSupportsListingMode = (node, listingMode) => {" in script
    assert "if (providerCountry && providerCountry !== normalizedCountry) return;" in script
    assert "if (!providerSupportsListingMode(node, listingMode)) return;" in script
    assert "const selectedPlatforms = checkedProviderValuesForCountry(form, countryCode, listingMode);" in script
    assert 'data-country-code="${escapeHtml(option.country_code)}"' in script
    assert 'data-listing-modes="${escapeHtml(option.supported_listing_modes.join(\',\'))}"' in script


