def test_property_workspace_payload_keeps_saved_brief_when_run_snapshot_is_old() -> None:
    payload = landing_property_workspace_payload.property_workspace_payload(
        "properties",
        status={"workspace": {"name": "Old Run Brief Office"}, "channels": {}},
        property_state={
            "commercial": {},
            "billing_truth": {},
            "preferences": {
                "country_code": "AT",
                "listing_mode": "rent",
                "location_query": "1020 Vienna",
                "property_type": "apartment",
                "selected_platforms": ["willhaben"],
                "max_price_eur": 26000,
            },
            "run": {
                "run_id": "run-old-budget",
                "status": "processed",
                "brief_preferences_stale": True,
                "property_search_preferences": {
                    "country_code": "AT",
                    "listing_mode": "rent",
                    "location_query": "1020 Vienna",
                    "property_type": "apartment",
                    "selected_platforms": ["willhaben"],
                    "max_price_eur": 1200,
                },
                "summary": {
                    "status": "processed",
                    "brief_preferences_stale": True,
                    "brief_snapshot_status": "old_run",
                    "filtered_total": 22,
                    "held_back_total": 22,
                    "sources": [],
                },
            },
            "run_health": {"status": "processed", "status_label": "Finished"},
            "preference_bundle": {},
            "search_agents": [],
        },
    )

    brief_preferences = dict(payload["decision_workbench"]["brief_preferences"])
    workbench = dict(payload["decision_workbench"])
    run = dict(workbench["run"])
    run_summary = dict(run["summary"])

    assert brief_preferences["max_price_eur"] == 26000
    assert brief_preferences["max_price_eur"] != 1200
    assert run["status_label"] == "Older search"
    assert run["filtered_total"] == 0
    assert run["held_back_total"] == 0
    assert run_summary["brief_snapshot_status"] == "old_run"
    assert run_summary["filtered_total"] == 0
    assert run_summary["held_back_total"] == 0
    assert run_summary["previous_filtered_total"] == 22
    assert workbench["suppression_rows"][0]["rule_key"] == "Older search snapshot"
    assert workbench["counterfactual_rows"][0]["adjustments"] == {}
    assert workbench["empty_outcome"]["active_rule"] == "Older search"
    assert "current search settings" in workbench["empty_outcome"]["next_move"]


