def test_property_map_tile_fetch_sets_user_agent_timeout_and_returns_response_bytes(monkeypatch) -> None:
    monkeypatch.setenv("PROPERTYQUARRY_MAP_TILE_NETWORK_ENABLED", "1")
    observed: dict[str, object] = {}

    class _TileResponse:
        def __enter__(self):
            return self

        def __exit__(self, exc_type, exc, tb) -> None:
            return None

        def read(self) -> bytes:
            return b"synthetic-tile-bytes"

    def _open_tile(request, *, timeout):
        observed["url"] = request.full_url
        observed["user_agent"] = request.get_header("User-agent")
        observed["timeout"] = timeout
        return _TileResponse()

    payload = landing_view_models._fetch_property_map_tile(
        "https://tile.openstreetmap.org/10/1/1.png",
        timeout_seconds=2.5,
        opener=_open_tile,
    )

    assert payload == b"synthetic-tile-bytes"
    assert observed == {
        "url": "https://tile.openstreetmap.org/10/1/1.png",
        "user_agent": "PropertyQuarry/1.0",
        "timeout": 2.5,
    }


def test_property_map_preview_selected_overlay_keeps_real_map_detail_visible(monkeypatch, tmp_path: Path) -> None:
    monkeypatch.setenv("EA_ARTIFACTS_DIR", str(tmp_path))

    tile = Image.new("RGB", (256, 256), (235, 231, 222))
    draw = ImageDraw.Draw(tile, "RGBA")
    for x in range(-40, 300, 18):
        draw.line([(x, 0), (x + 120, 256)], fill=(72, 66, 60, 145), width=2)
    for y in range(0, 280, 14):
        draw.line([(0, y), (256, y - 54)], fill=(96, 90, 82, 132), width=2)
    draw.polygon([(0, 190), (74, 168), (132, 180), (256, 146), (256, 256), (0, 256)], fill=(166, 194, 209, 168))
    draw.line([(54, 36), (210, 224)], fill=(188, 164, 126, 168), width=10)
    draw.line([(28, 210), (228, 72)], fill=(214, 201, 176, 122), width=8)
    tile_bytes = io.BytesIO()
    tile.save(tile_bytes, format="PNG")

    monkeypatch.setattr(
        landing_view_models,
        "_fetch_property_map_tile",
        lambda _url, *, timeout_seconds=6.0: tile_bytes.getvalue(),
    )

    base_path = landing_view_models._cached_preview_png_path(
        cache_key={"kind": "map-overlay-visibility-base"},
        center_lat=48.2142,
        center_lon=16.3817,
        zoom=13,
        overlay_rows=[],
        draw_overlay=False,
    )
    overlay_path = landing_view_models._cached_preview_png_path(
        cache_key={"kind": "map-overlay-visibility-overlay"},
        center_lat=48.2142,
        center_lon=16.3817,
        zoom=13,
        overlay_rows=[
            {
                "label": "1020 Vienna",
                "selected": True,
                "path": "M 168 92 L 472 92 L 472 286 L 168 286 Z",
            }
        ],
        draw_overlay=True,
    )

    base_image = Image.open(base_path).convert("RGB").crop((182, 106, 458, 272))
    overlay_image = Image.open(overlay_path).convert("RGB").crop((182, 106, 458, 272))

    base_stats = ImageStat.Stat(base_image)
    overlay_stats = ImageStat.Stat(overlay_image)
    base_edges = ImageStat.Stat(base_image.convert("L").filter(ImageFilter.FIND_EDGES)).mean[0]
    overlay_edges = ImageStat.Stat(overlay_image.convert("L").filter(ImageFilter.FIND_EDGES)).mean[0]

    # The selected area should pick up a visible red tint.
    base_red_bias = base_stats.mean[0] - base_stats.mean[1]
    overlay_red_bias = overlay_stats.mean[0] - overlay_stats.mean[1]
    assert overlay_red_bias >= base_red_bias + 18.0
    assert overlay_stats.mean[2] <= base_stats.mean[2] - 12.0

    # But the underlying street and water detail still needs to stay readable.
    assert overlay_edges >= base_edges * 0.75
    assert sum(overlay_stats.stddev) / 3 >= 14.5


def test_property_map_preview_point_focus_card_meets_flagship_gate(monkeypatch, tmp_path: Path) -> None:
    from scripts import propertyquarry_map_preview_flagship_gate as gate

    monkeypatch.setenv("EA_ARTIFACTS_DIR", str(tmp_path))

    tile = Image.new("RGB", (256, 256), (235, 231, 222))
    draw = ImageDraw.Draw(tile, "RGBA")
    for x in range(-40, 300, 24):
        draw.line([(x, 0), (x + 120, 256)], fill=(72, 66, 60, 126), width=2)
    for y in range(0, 280, 18):
        draw.line([(0, y), (256, y - 54)], fill=(96, 90, 82, 118), width=2)
    draw.polygon([(0, 190), (74, 168), (132, 180), (256, 146), (256, 256), (0, 256)], fill=(166, 194, 209, 168))
    draw.line([(54, 36), (210, 224)], fill=(188, 164, 126, 168), width=10)
    draw.line([(28, 210), (228, 72)], fill=(214, 201, 176, 122), width=8)
    tile_bytes = io.BytesIO()
    tile.save(tile_bytes, format="PNG")

    monkeypatch.setattr(
        landing_view_models,
        "_fetch_property_map_tile",
        lambda _url, *, timeout_seconds=6.0: tile_bytes.getvalue(),
    )

    preview_url = landing_view_models._cached_preview_image_url(
        cache_key={"kind": "map-point-flagship", "query": "Trieben, AT"},
        center_lat=47.4896,
        center_lon=14.4875,
        zoom=10,
        pin=(320.0, 184.0),
        draw_overlay=False,
    )
    preview_path = tmp_path / "map_previews" / preview_url.rsplit("/", 1)[-1]

    receipt = gate.build_map_preview_flagship_receipt(
        base_url="http://localhost",
        host_header="",
        api_token="",
        principal_id="",
        image_urls=[preview_path.as_uri()],
        discover_routes=[],
        timeout_seconds=1.0,
        settle_seconds=0.0,
        min_preview_count=1,
        canonical_fallback=False,
    )

    assert receipt["status"] == "pass"
    assert receipt["preview_results"][0]["metrics"]["stddev_mean"] >= 18.0


def test_property_scope_preview_map_only_uses_slightly_wider_padding_for_full_district_shapes(monkeypatch) -> None:
    captured: list[dict[str, object]] = []

    def _fake_boundary_preview(**kwargs):
        captured.append(dict(kwargs))
        return {
            "image_url": "/app/api/property/map-previews/framed.png",
            "summary": kwargs.get("normalized_query"),
            "preview_kind": "osm_district_overlay",
            "has_district_overlay": True,
            "district_rows": [{"label": "1020 Vienna", "selected": True, "path": "M0 0 L1 0 L1 1 Z"}],
        }

    monkeypatch.setattr(landing_view_models, "_build_scope_boundary_preview", _fake_boundary_preview)

    preview = landing_view_models._property_scope_preview_map_only("AT", "vienna", "1020 Vienna")

    assert preview["preview_kind"] == "osm_district_overlay"
    assert captured
    assert captured[0]["padding_ratio"] == 0.19


def test_property_scope_preview_map_only_schedules_real_map_without_final_placeholder(monkeypatch, tmp_path: Path) -> None:
    monkeypatch.setenv("EA_ARTIFACTS_DIR", str(tmp_path))
    monkeypatch.setattr(
        landing_view_models,
        "_nominatim_boundary_record",
        lambda query: (_ for _ in ()).throw(AssertionError("agents first paint must not call Nominatim")),
    )
    render_calls: list[dict[str, object]] = []
    monkeypatch.setattr(
        landing_view_models,
        "_cached_preview_png_path",
        lambda **kwargs: render_calls.append(dict(kwargs)) or (tmp_path / "rendered-later.png"),
    )

    preview = landing_view_models._property_scope_preview_map_only("AT", "vienna", "1020 Vienna, 1200 Vienna")

    assert preview["preview_kind"] == "osm_district_overlay"
    assert preview["has_district_overlay"] is True
    image_url = str(preview["image_url"])
    assert image_url.startswith("/app/api/property/map-previews/")
    assert "0000000000000000000000000000000000000000" not in image_url
    preview_id = re.search(r"/([0-9a-f]{40})\.png$", image_url)
    assert preview_id
    preview_file = tmp_path / "map_previews" / f"{preview_id.group(1)}.png"
    assert not preview_file.exists()
    deadline = time.monotonic() + 1.0
    while not render_calls and time.monotonic() < deadline:
        time.sleep(0.01)
    assert render_calls


def test_property_scope_preview_boundary_framing_adds_small_map_breathing_room() -> None:
    bounds = (16.356, 48.202, 16.379, 48.216)

    west, south, east, north = landing_view_models._expand_geo_bounds(bounds)
    lon_span = bounds[2] - bounds[0]
    lat_span = bounds[3] - bounds[1]
    lon_pad = bounds[0] - west
    lat_pad = bounds[1] - south

    assert west < bounds[0]
    assert south < bounds[1]
    assert east > bounds[2]
    assert north > bounds[3]
    assert lon_pad >= lon_span * 0.10
    assert lat_pad >= lat_span * 0.10
    assert lon_pad <= lon_span * 0.23
    assert lat_pad <= lat_span * 0.23


def test_property_scope_preview_zoom_uses_tightest_unclipped_tile_crop() -> None:
    single_district_raw_bounds = (16.365, 48.197, 16.456, 48.235)
    single_district_bounds = landing_view_models._expand_geo_bounds(single_district_raw_bounds)
    assert landing_view_models._preview_zoom_for_bounds(
        single_district_bounds,
        fit_bounds=single_district_raw_bounds,
    ) == 13

    adjacent_district_raw_bounds = (16.35, 48.197, 16.456, 48.26)
    adjacent_district_bounds = landing_view_models._expand_geo_bounds(adjacent_district_raw_bounds)
    assert landing_view_models._preview_zoom_for_bounds(
        adjacent_district_bounds,
        fit_bounds=adjacent_district_raw_bounds,
    ) == 12


