def test_property_workspace_payload_keeps_visual_requests_active_across_reload_states() -> None:
    payload = landing_property_workspace_payload.property_workspace_payload(
        "shortlist",
        status={},
        property_state={
            "commercial": {},
            "billing_truth": {},
            "preferences": {
                "country_code": "AT",
                "listing_mode": "rent",
                "search_goal": "home",
                "location_query": "1020 Vienna",
            },
            "run": {
                "run_id": "run-visual-active",
                "property_search_preferences": {
                    "country_code": "AT",
                    "listing_mode": "rent",
                    "search_goal": "home",
                    "location_query": "1020 Vienna",
                },
                "summary": {
                    "ranked_candidates": [
                        {
                            "candidate_ref": "candidate-tour-rendering",
                            "title": "Rendering tour state",
                            "property_url": "https://example.test/rendering-tour",
                            "fit_score": 78,
                            "tour_status": "rendering",
                            "tour_eta_minutes": "10",
                            "property_facts": {
                                "postal_name": "1020 Wien",
                                "price_display": "EUR 1,540",
                                "area_m2": 71,
                                "rooms": 2,
                            },
                        },
                        {
                            "candidate_ref": "candidate-flythrough-repair",
                            "title": "Repairing walkthrough state",
                            "property_url": "https://example.test/repairing-walkthrough",
                            "fit_score": 74,
                            "flythrough_status": "repairing",
                            "property_facts": {
                                "postal_name": "1020 Wien",
                                "price_display": "EUR 1,620",
                                "area_m2": 76,
                                "rooms": 3,
                            },
                        },
                        {
                            "candidate_ref": "candidate-flythrough-terminal-drift",
                            "title": "Terminal walkthrough state",
                            "property_url": "https://example.test/terminal-walkthrough",
                            "fit_score": 72,
                            "flythrough_status": "queued",
                            "flythrough_reason": "magicfit_segment_render_failed",
                            "property_facts": {
                                "postal_name": "1020 Wien",
                                "price_display": "EUR 1,480",
                                "area_m2": 68,
                                "rooms": 2,
                            },
                        },
                    ],
                    "sources": [],
                },
            },
        },
    )

    results = list(payload["decision_workbench"]["results"] or [])
    assert results[0]["tour"]["status"] == "processing"
    assert results[0]["tour"]["label"] == "3D tour rendering"
    assert results[0]["tour"]["status_detail"] == "Tour is rendering now."
    assert results[1]["flythrough"]["status"] == "processing"
    assert results[1]["flythrough"]["label"] == "Walkthrough in progress"
    assert results[1]["flythrough"]["recovery_label"] == "Automatic repair"
    terminal = next(row for row in results if row["candidate_ref"] == "candidate-flythrough-terminal-drift")
    assert terminal["flythrough"]["status"] == "blocked"
    assert terminal["flythrough"]["label"] == "Walkthrough not ready"
    assert terminal["flythrough"]["status_detail"] == "Walkthrough could not be rendered from this listing yet."


