def test_property_workspace_payload_sanitizes_error_code_1010_in_search_cards() -> None:
    raw_message = "Could not complete. Error code: 1010 while fetching listings."
    expected_safe_message = property_surface_state.property_run_customer_safe_status_detail(
        "failed",
        raw_message,
        summary={
            "status": "failed",
            "sources_total": 3,
            "sources_completed": 0,
            "listing_total": 0,
            "repair_status": "repairing",
            "repair_status_label": "Retrying",
        },
        prefer_repair_step=True,
    )
    payload = landing_routes._property_workspace_payload(
        "search",
        status={"workspace": {"name": "Search"}, "channels": {}},
        property_state={
            "preferences": {"country_code": "AT", "listing_mode": "buy"},
            "commercial": {"current_plan_label": "Agent", "current_plan_key": "agent"},
            "preference_bundle": {},
            "run": {
                "run_id": "run-1010-raw",
                "status": "failed",
                "progress": 100,
                "message": raw_message,
                "summary": {
                    "status": "failed",
                    "sources_total": 3,
                    "sources_completed": 0,
                    "listing_total": 0,
                    "repair_status": "repairing",
                    "repair_status_label": "Retrying",
                },
            },
        },
    )

    assert payload["run_payload"]["message"] == expected_safe_message
    assert payload["decision_workbench"]["run"]["message"] == expected_safe_message
    assert "error code: 1010" not in payload["decision_workbench"]["client_run"]["message"].lower()
    assert "error code: 1010" not in expected_safe_message.lower()
    serialized_payload = json.dumps(payload, sort_keys=True).lower()
    assert "error code: 1010" not in serialized_payload


def test_property_workspace_payload_bounds_properties_first_paint_results() -> None:
    heavy_blob = "x" * 5000
    ranked_candidates = [
        {
            "candidate_ref": f"candidate-{index}",
            "title": f"Candidate {index}",
            "fit_score": 100 - index,
            "property_url": f"https://example.test/listing/{index}",
            "source_label": "Willhaben",
            "detail": heavy_blob,
            "property_facts": {
                "price_display": "EUR 1,200",
                "area_m2": 72,
                "rooms": 3,
                "postal_name": "1020 Vienna",
            },
        }
        for index in range(60)
    ]

    payload = landing_routes._property_workspace_payload(
        "properties",
        status={"workspace": {"name": "Bounded Properties"}, "channels": {}},
        property_state={
            "preferences": {"country_code": "AT", "listing_mode": "rent", "location_query": "1020 Vienna"},
            "commercial": {"current_plan_label": "Agent", "current_plan_key": "agent"},
            "preference_bundle": {},
            "run": {
                "run_id": "run-bounded",
                "status": "completed",
                "progress": 100,
                "summary": {
                    "status": "completed",
                    "listing_total": 60,
                    "ranked_total": 60,
                    "sources": [
                        {
                            "source_label": "Willhaben",
                            "top_candidates": ranked_candidates,
                            "source_html": heavy_blob,
                        }
                    ],
                    "ranked_candidates": ranked_candidates,
                },
            },
        },
    )

    workbench = dict(payload.get("decision_workbench") or {})
    run = dict(workbench.get("run") or {})
    summary = dict(run.get("summary") or {})
    rendered_results = [dict(row) for row in list(workbench.get("results") or []) if isinstance(row, dict)]
    serialized_payload = json.dumps(payload, sort_keys=True)

    assert summary["listing_total"] == 60
    assert summary["ranked_total"] == 60
    assert "ranked_candidates" not in summary
    assert "top_candidates" not in json.dumps(summary, sort_keys=True)
    assert "source_html" not in json.dumps(summary, sort_keys=True)
    assert len(rendered_results) == 24
    assert "Candidate 0" in serialized_payload
    assert "Candidate 59" not in serialized_payload
    assert heavy_blob not in serialized_payload


