def test_propertyquarry_mobile_what_matters_distance_rows_are_not_clipped() -> None:
    repo_root = Path(__file__).resolve().parents[1]
    body = (repo_root / "ea/app/templates/app/property_decision_workbench.html").read_text(encoding="utf-8")
    what_matters_panel_match = re.search(
        r'@media \(max-width: 760px\).*?'
        r'\.pqx-surface-search \.pqx-form\[data-property-active-step="children"\] '
        r'\.pqx-what-matters-panel\s*\{(?P<body>.*?)\}',
        body,
        re.S,
    )
    assert what_matters_panel_match is not None
    what_matters_panel_block = what_matters_panel_match.group("body")
    assert "position: static;" in what_matters_panel_block
    assert "max-height: calc(100svh - 28px);" in what_matters_panel_block
    assert "overflow: hidden;" in what_matters_panel_block
    assert "padding: 0;" in what_matters_panel_block
    assert "position: fixed;" not in what_matters_panel_block

    brief_panel_match = re.search(
        r'@media \(max-width: 760px\).*?'
        r'\.pqx-shell\[data-pqx-surface="search"\] \.pqx-brief-drawer-panel\s*\{(?P<body>.*?)\}',
        body,
        re.S,
    )
    assert brief_panel_match is not None
    brief_panel_block = brief_panel_match.group("body")
    assert "min-height: 0;" in brief_panel_block
    assert "max-height: none;" in brief_panel_block
    assert "overflow: visible;" in brief_panel_block

    advanced_grid_match = re.search(
        r'@media \(max-width: 760px\).*?'
        r'\.pqx-surface-search \.pqx-form\[data-property-active-step="children"\] '
        r'\.pqx-what-matters-panel \.pqx-advanced-panel-grid\s*\{(?P<body>.*?)\}',
        body,
        re.S,
    )
    assert advanced_grid_match is not None
    advanced_grid_block = advanced_grid_match.group("body")
    assert "max-height: 100%;" in advanced_grid_block
    assert "overflow-y: auto;" in advanced_grid_block
    assert "overscroll-behavior: contain;" in advanced_grid_block
    assert "-webkit-overflow-scrolling: touch;" in advanced_grid_block

    active_group_match = re.search(
        r'@media \(max-width: 760px\).*?'
        r'\.pqx-what-matters-panel \.pqx-choice-groupbox'
        r'\[data-what-matters-group\]\[open\]\[data-active-distance-rows="true"\],\s*'
        r'\.pqx-what-matters-panel \.pqx-choice-groupbox'
        r'\[data-what-matters-group\]\[data-mobile-distance-control-active="true"\]\s*\{'
        r'(?P<body>.*?)\}',
        body,
        re.S,
    )
    assert active_group_match is not None
    active_group_block = active_group_match.group("body")
    assert "overflow: visible;" in active_group_block
    assert "contain: none;" in active_group_block
    assert "padding-bottom: calc(12px + env(safe-area-inset-bottom, 0px));" in active_group_block

    open_list_match = re.search(
        r'@media \(max-width: 760px\).*?'
        r'\.pqx-what-matters-panel \.pqx-choice-groupbox'
        r'\[data-what-matters-group\]\[open\] \.pqx-pref-list\s*\{(?P<body>.*?)\}',
        body,
        re.S,
    )
    assert open_list_match is not None
    open_list_block = open_list_match.group("body")
    assert "max-height: none;" in open_list_block
    assert "overflow: visible;" in open_list_block
    assert "padding-right: 0;" in open_list_block

    active_list_match = re.search(
        r'@media \(max-width: 760px\).*?'
        r'\.pqx-what-matters-panel \.pqx-choice-groupbox'
        r'\[data-what-matters-group\]\[open\]\[data-active-distance-rows="true"\] \.pqx-pref-list\s*\{'
        r'(?P<body>.*?)\}',
        body,
        re.S,
    )
    assert active_list_match is not None
    active_list_block = active_list_match.group("body")
    assert "max-height: none;" in active_list_block
    assert "overflow: visible;" in active_list_block
    assert "padding-bottom: 8px;" in active_list_block
    mobile_block_end = body.find("@keyframes pqx-soft-reveal", active_list_match.end())
    assert mobile_block_end > active_list_match.end()
    mobile_block = body[active_list_match.end():mobile_block_end]

    mobile_distance_row = re.search(
        r'\.pqx-what-matters-panel \.pqx-keyword-priority-row'
        r'\[data-keyword-distance-enabled="true"\]\s*\{(?P<body>.*?)\}',
        mobile_block,
        re.S,
    )
    assert mobile_distance_row is not None
    assert "grid-template-columns: minmax(0, 1fr);" in mobile_distance_row.group("body")
    assert "min-height: 0;" in mobile_distance_row.group("body")

    assert (
        '.pqx-what-matters-panel .pqx-pref-row select,\n'
        '      .pqx-what-matters-panel .pqx-keyword-priority-row select,\n'
        '      .pqx-what-matters-panel .pqx-school-priority-row select {\n'
        '        min-height: 44px;\n'
        '        width: 100%;'
    ) in mobile_block
    assert (
        '.pqx-what-matters-panel .pqx-pref-row-controls > :only-child {\n'
        '        grid-column: 1 / -1;\n'
        '        width: 100%;'
    ) in mobile_block
    assert '.pqx-what-matters-mobile-tools {\n        display: block;' in body
    assert '.pqx-what-matters-head .pqx-actions {\n        display: none;' in body
    assert '.pqx-what-matters-more {\n        margin-top: 6px;' in body


